module RefModule (
    input [3:0] a,
    input [3:0] b,
    output a_eq_b,
    output a_lt_b,
    output a_gt_b
);

      wire _n01 = a[0] ^ b[0];
  wire _n02 = a[1] ^ b[1];
  wire _n03 = a[2] ^ b[2];
  wire _n04 = a[3] ^ b[3];
  assign a_eq_b = ~_n01 & ~_n02 & ~_n03 & ~_n04;
    assign a_lt_b = (a < b);
    assign a_gt_b = (a > b);

endmodule
